Here is a JavaScript construct to calculate the factorial of x:

function factorial(x) {
  if (x === 0 || x === 1) return 1;
  let result = 1;
  for (let i = 2; i <= x; i++) {
    result *= i;
  }
  return result;
}

let x = 7;
console.log("Factorial of " + x + " is " + factorial(x));
